// Script Continued Below
var OU_uiAction = Class.create();
OU_uiAction.prototype = {
    initialize: function() {
    },

	// TODO - NOTE: This occurs in multiple functions and needs to go into a common script include
	trimComments: function(strComment) {
		var maxComment = 500;
		// STRY0097883
		strComment = strComment + '';
		var userComments = strComment.replace(/<\/?[^>]+(>|$)/g, "").toString();
		userComments = userComments.length > maxComment ? userComments.substring(0,maxComment-3) + '...' : userComments;
		return userComments;

	},

	// STRY0108329 - added for OU requests
	uiAction_SubmitOURequest: function(request) {
		// currently no comments or work notes for OU.  Should we add activity?
		request.u_requested_by = gs.getUserID();
		request.u_requested = new GlideDateTime();
		request.insert();
		// STRY0101474 
		this.updateOUOpenRequestCount(request);
		gs.addInfoMessage(gs.getMessage('Request Submitted'));
	},

	uiAction_AcceptOURequest: function(request) {
		// STRY0101474 - did some cleanup
		this._RespondOURequest(request, 
								gs.getMessage('Tasker - Request {0} was not marked complete.  It is most likely a permissions issue.',[request.number]), 
								gs.getMessage('Approved'));
	},	

	uiAction_RejectOURequest: function(request) {
		// STRY0101474 - did some cleanup
		this._RespondOURequest(request, 
								gs.getMessage('Tasker - Request {0} was not rejected.  It is most likely a permissions issue.',[request.number]), 
								gs.getMessage('Rejected'));
	},

	// STRY0101474 - did some cleanup
	_RespondOURequest: function(request, errorMessage, response) {
		if(request.u_ou_parent) {
			var allow = new uiConditionCheck().RespondOURequest(request);
			if (allow) {
				var todaysDate = new GlideDateTime();
				// TODO - multilanguage - this might be enough
				request.u_status = gs.getMessage('Completed');
				// TODO - multilanguage - this might be enough
				request.u_response = response;
				request.u_responded_by = gs.getUserID();
				request.u_responded = todaysDate;
				request.update();

				// STRY0101474 
				this.updateOUOpenRequestCount(request);

				gs.addInfoMessage(gs.getMessage('Tasker - The Organizational Request for ({0}) request to: ({1})  was completed by {2} with the following comments: {3}', [request.getDisplayValue('u_ou_parent'),
									request.getDisplayValue('u_request_type'), gs.getUserDisplayName(), this.trimComments(request.u_response_comments)])
									);
			} else gs.addErrorMessage(errorMessage);
		} else gs.addErrorMessage(errorMessage);
	},	

	// STRY0101474 - added an indicator to show outstanding request exists
	updateOUOpenRequestCount: function(request){
		// note: cannot be glide record secure.  we need to update this count and the user does not have permission to update the OU.
		var gaOU = new GlideAggregate('x_153465_discovert_tasker_requests');
		gaOU.addQuery('u_ou_parent',request.getValue('u_ou_parent'));
		gaOU.addQuery('u_status','In progress');
		gaOU.addAggregate('COUNT');
		gaOU.query();
		var numOpenRequests = 0;
		if(gaOU.next())
			numOpenRequests = gaOU.getAggregate('COUNT');

		var grOU = new GlideRecord('x_153465_discovert_discover_office_hierarchy');
		if(grOU.get(request.getValue('u_ou_parent'))){
			if(parseInt(grOU.u_outstanding_request_count)!=numOpenRequests){
				grOU.u_outstanding_request_count = numOpenRequests;
				grOU.update();
			}
		}

	},

    type: 'OU_uiAction'
};
